/**
 * College data — loaded at build time.
 * 
 * colleges.json is generated by scripts/fetch-colleges.js (GitHub Actions).
 * When it exists, Vite bundles all 3,000 colleges automatically.
 * The fallback list below is only used if colleges.json hasn't been generated yet.
 */

import collegesFromJson from './colleges.json' with { type: 'json' }

// colleges.json structure: { _meta: { tierMultipliers, computedAt }, colleges: [...] }
export const COLLEGES         = collegesFromJson.colleges
export const TIER_MULTIPLIERS_FROM_SCORECARD = collegesFromJson._meta?.tierMultipliers ?? null

export const INCOME_BRACKETS = [
  { label: 'Under $30,000',    key: 'low'  },
  { label: '$30,001–$48,000',  key: 'mid1' },
  { label: '$48,001–$75,000',  key: 'mid2' },
  { label: '$75,001–$110,000', key: 'mid3' },
  { label: 'Over $110,000',    key: 'high' },
]
